import java.nio.charset.StandardCharsets;
import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting input size to prevent buffer overflow
        byte[] buffer = new byte[10];
        byte[] nameBytes = name.getBytes(StandardCharsets.UTF_8);

        if (nameBytes.length <= buffer.length) {
            System.arraycopy(nameBytes, 0, buffer, 0, nameBytes.length);
        } else {
            System.arraycopy(nameBytes, 0, buffer, 0, buffer.length);
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

